import React, { useState, useRef } from 'react';
import { Project, Certificate, BlogPost, ProjectCategory, BlogPlatform } from '../types';

interface AdminPanelProps {
    onLogout: () => void;
    projects: Project[];
    certificates: Certificate[];
    blogPosts: BlogPost[];
    onAddProject: (p: Omit<Project, 'id'>) => void;
    onDeleteProject: (id: string) => void;
    onAddCertificate: (c: Omit<Certificate, 'id'>) => void;
    onDeleteCertificate: (id: string) => void;
    onAddBlogPost: (b: Omit<BlogPost, 'id'>) => void;
    onDeleteBlogPost: (id: string) => void;
}

type Tab = 'projects' | 'certificates' | 'blog';

const AdminPanel: React.FC<AdminPanelProps> = ({ 
    onLogout, 
    projects, 
    certificates, 
    blogPosts,
    onAddProject,
    onDeleteProject,
    onAddCertificate,
    onDeleteCertificate,
    onAddBlogPost,
    onDeleteBlogPost
}) => {
    const [activeTab, setActiveTab] = useState<Tab>('projects');

    // Forms State
    const [projectForm, setProjectForm] = useState({ title: '', description: '', tags: '', githubUrl: '', liveUrl: '', category: ProjectCategory.ML, image: '' });
    const [certForm, setCertForm] = useState({ title: '', issuer: '', url: '', image: '' });
    const [blogForm, setBlogForm] = useState({ title: '', description: '', platform: BlogPlatform.MEDIUM, url: '', image: '' });

    // File Input Refs to clear them after submit
    const projectFileRef = useRef<HTMLInputElement>(null);
    const certFileRef = useRef<HTMLInputElement>(null);
    const blogFileRef = useRef<HTMLInputElement>(null);

    // Helper to convert file to Base64
    const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, setForm: any, prevForm: any) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setForm({ ...prevForm, image: reader.result as string });
            };
            reader.readAsDataURL(file);
        }
    };

    const handleAddProject = (e: React.FormEvent) => {
        e.preventDefault();
        onAddProject({
            ...projectForm,
            tags: projectForm.tags.split(',').map(t => t.trim()),
        });
        setProjectForm({ title: '', description: '', tags: '', githubUrl: '', liveUrl: '', category: ProjectCategory.ML, image: '' });
        if (projectFileRef.current) projectFileRef.current.value = '';
    };

    const handleAddCert = (e: React.FormEvent) => {
        e.preventDefault();
        onAddCertificate(certForm);
        setCertForm({ title: '', issuer: '', url: '', image: '' });
        if (certFileRef.current) certFileRef.current.value = '';
    };

    const handleAddBlog = (e: React.FormEvent) => {
        e.preventDefault();
        onAddBlogPost(blogForm);
        setBlogForm({ title: '', description: '', platform: BlogPlatform.MEDIUM, url: '', image: '' });
        if (blogFileRef.current) blogFileRef.current.value = '';
    };

    return (
        <section className="min-h-screen bg-gray-50 dark:bg-dark-bg animate-fade-in-up">
            <div className="container mx-auto px-6 py-12">
                <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-4">
                    <div>
                        <h1 className="text-3xl font-bold text-gray-900 dark:text-white">Admin Dashboard</h1>
                        <p className="text-gray-500 dark:text-gray-400 mt-1">Manage Content: Projects, Certificates, Blogs</p>
                    </div>
                    <button onClick={onLogout} className="px-5 py-2.5 bg-red-500 hover:bg-red-600 text-white rounded-lg shadow-md transition-colors">
                        Logout
                    </button>
                </div>

                <div className="flex space-x-4 mb-8 border-b dark:border-gray-700 pb-2 overflow-x-auto">
                    {(['projects', 'certificates', 'blog'] as Tab[]).map(tab => (
                        <button 
                            key={tab}
                            onClick={() => setActiveTab(tab)}
                            className={`px-4 py-2 capitalize font-medium transition-colors border-b-2 ${activeTab === tab ? 'border-primary text-primary dark:text-primary-light' : 'border-transparent text-gray-500 hover:text-gray-700 dark:text-gray-400'}`}
                        >
                            {tab}
                        </button>
                    ))}
                </div>

                {/* PROJECT TAB */}
                {activeTab === 'projects' && (
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                        {/* Add Form */}
                        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg h-fit">
                            <h3 className="text-xl font-bold mb-4">Add Project</h3>
                            <form onSubmit={handleAddProject} className="space-y-4">
                                <input type="text" placeholder="Title" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={projectForm.title} onChange={e => setProjectForm({...projectForm, title: e.target.value})} />
                                <textarea placeholder="Description" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={projectForm.description} onChange={e => setProjectForm({...projectForm, description: e.target.value})} />
                                <input type="text" placeholder="Tags (comma separated)" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={projectForm.tags} onChange={e => setProjectForm({...projectForm, tags: e.target.value})} />
                                <div className="grid grid-cols-2 gap-4">
                                    <input type="url" placeholder="GitHub URL" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={projectForm.githubUrl} onChange={e => setProjectForm({...projectForm, githubUrl: e.target.value})} />
                                    <input type="url" placeholder="Live URL (Optional)" className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={projectForm.liveUrl} onChange={e => setProjectForm({...projectForm, liveUrl: e.target.value})} />
                                </div>
                                <div>
                                    <label className="block text-sm text-gray-600 dark:text-gray-400 mb-1">Project Image</label>
                                    <input 
                                        type="file" 
                                        ref={projectFileRef}
                                        accept="image/*" 
                                        onChange={(e) => handleImageUpload(e, setProjectForm, projectForm)} 
                                        className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-primary/10 file:text-primary hover:file:bg-primary/20"
                                    />
                                    {projectForm.image && <img src={projectForm.image} alt="Preview" className="mt-2 h-20 w-auto rounded border" />}
                                </div>
                                <select className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={projectForm.category} onChange={e => setProjectForm({...projectForm, category: e.target.value as ProjectCategory})}>
                                    {Object.values(ProjectCategory).filter(c => c !== ProjectCategory.ALL).map(c => <option key={c} value={c}>{c}</option>)}
                                </select>
                                <button type="submit" className="w-full bg-primary text-white py-2 rounded hover:bg-primary-dark">Add Project</button>
                            </form>
                        </div>

                        {/* List */}
                        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg">
                             <h3 className="text-xl font-bold mb-4">Existing Projects</h3>
                             <div className="space-y-4 max-h-[600px] overflow-y-auto">
                                {projects.map(p => (
                                    <div key={p.id} className="flex justify-between items-start border-b dark:border-gray-700 pb-2">
                                        <div className="flex items-center gap-3">
                                            {p.image && <img src={p.image} alt={p.title} className="w-12 h-12 object-cover rounded" />}
                                            <div>
                                                <p className="font-bold">{p.title}</p>
                                                <p className="text-xs text-gray-500">{p.category}</p>
                                            </div>
                                        </div>
                                        <button onClick={() => onDeleteProject(p.id)} className="text-red-500 hover:text-red-700 text-sm">Delete</button>
                                    </div>
                                ))}
                             </div>
                        </div>
                    </div>
                )}

                {/* CERTIFICATES TAB */}
                {activeTab === 'certificates' && (
                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg h-fit">
                            <h3 className="text-xl font-bold mb-4">Add Certificate</h3>
                            <form onSubmit={handleAddCert} className="space-y-4">
                                <input type="text" placeholder="Title" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={certForm.title} onChange={e => setCertForm({...certForm, title: e.target.value})} />
                                <input type="text" placeholder="Issuer" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={certForm.issuer} onChange={e => setCertForm({...certForm, issuer: e.target.value})} />
                                <input type="url" placeholder="Certificate URL" className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={certForm.url} onChange={e => setCertForm({...certForm, url: e.target.value})} />
                                <div>
                                    <label className="block text-sm text-gray-600 dark:text-gray-400 mb-1">Certificate Image (Optional)</label>
                                    <input 
                                        type="file" 
                                        ref={certFileRef}
                                        accept="image/*" 
                                        onChange={(e) => handleImageUpload(e, setCertForm, certForm)} 
                                        className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-primary/10 file:text-primary hover:file:bg-primary/20"
                                    />
                                    {certForm.image && <img src={certForm.image} alt="Preview" className="mt-2 h-20 w-auto rounded border" />}
                                </div>
                                <button type="submit" className="w-full bg-primary text-white py-2 rounded hover:bg-primary-dark">Add Certificate</button>
                            </form>
                        </div>
                        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg">
                             <h3 className="text-xl font-bold mb-4">Existing Certificates</h3>
                             <div className="space-y-4 max-h-[600px] overflow-y-auto">
                                {certificates.map(c => (
                                    <div key={c.id} className="flex justify-between items-center border-b dark:border-gray-700 pb-2">
                                        <div className="flex items-center gap-3">
                                            {c.image && <img src={c.image} alt={c.title} className="w-12 h-12 object-cover rounded" />}
                                            <div>
                                                <p className="font-bold">{c.title}</p>
                                                <p className="text-xs text-gray-500">{c.issuer}</p>
                                            </div>
                                        </div>
                                        <button onClick={() => onDeleteCertificate(c.id)} className="text-red-500 hover:text-red-700 text-sm">Delete</button>
                                    </div>
                                ))}
                             </div>
                        </div>
                     </div>
                )}

                {/* BLOG TAB */}
                {activeTab === 'blog' && (
                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg h-fit">
                            <h3 className="text-xl font-bold mb-4">Add Blog Post</h3>
                            <form onSubmit={handleAddBlog} className="space-y-4">
                                <input type="text" placeholder="Title" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={blogForm.title} onChange={e => setBlogForm({...blogForm, title: e.target.value})} />
                                <textarea placeholder="Description" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={blogForm.description} onChange={e => setBlogForm({...blogForm, description: e.target.value})} />
                                <select className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={blogForm.platform} onChange={e => setBlogForm({...blogForm, platform: e.target.value as BlogPlatform})}>
                                    {Object.values(BlogPlatform).map(p => <option key={p} value={p}>{p}</option>)}
                                </select>
                                <input type="url" placeholder="Post URL" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={blogForm.url} onChange={e => setBlogForm({...blogForm, url: e.target.value})} />
                                <div>
                                    <label className="block text-sm text-gray-600 dark:text-gray-400 mb-1">Blog Image (Optional)</label>
                                    <input 
                                        type="file" 
                                        ref={blogFileRef}
                                        accept="image/*" 
                                        onChange={(e) => handleImageUpload(e, setBlogForm, blogForm)} 
                                        className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-primary/10 file:text-primary hover:file:bg-primary/20"
                                    />
                                    {blogForm.image && <img src={blogForm.image} alt="Preview" className="mt-2 h-20 w-auto rounded border" />}
                                </div>
                                <button type="submit" className="w-full bg-primary text-white py-2 rounded hover:bg-primary-dark">Add Post</button>
                            </form>
                        </div>
                        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg">
                             <h3 className="text-xl font-bold mb-4">Existing Posts</h3>
                             <div className="space-y-4 max-h-[600px] overflow-y-auto">
                                {blogPosts.map(b => (
