const subheadings = [
  "Machine Learning & Deep Learning",
  "GenAI Projects",
  "MLOps"
];

const Home: React.FC = () => {
  const [subheadingIndex, setSubheadingIndex] = useState(0);
  const [typedSubheading, setTypedSubheading] = useState('');
  const [isDeleting, setIsDeleting] = useState(false);
  const [typingSpeed, setTypingSpeed] = useState(150);
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const handleTyping = () => {
      const currentSubheading = subheadings[subheadingIndex];
      if (isDeleting) {
        setTypedSubheading(currentSubheading.substring(0, typedSubheading.length - 1));
      } else {
        setTypedSubheading(currentSubheading.substring(0, typedSubheading.length + 1));
      }

      if (!isDeleting && typedSubheading === currentSubheading) {
        // Pause at end
        setTypingSpeed(2000);
        setIsDeleting(true);
      } else if (isDeleting && typedSubheading === '') {
        setIsDeleting(false);
        setSubheadingIndex((prevIndex) => (prevIndex + 1) % subheadings.length);
        setTypingSpeed(150);
      } else {
         setTypingSpeed(isDeleting ? 75 : 150);
      }
    };

    const timer = setTimeout(handleTyping, typingSpeed);
    return () => clearTimeout(timer);
  }, [typedSubheading, isDeleting, typingSpeed, subheadingIndex]);

  useEffect(() => {
    const handleScroll = () => {
      if (sectionRef.current) {
        const offset = window.scrollY;
        sectionRef.current.style.backgroundPositionY = `${offset * 0.5}px`;
      }
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);


  return (
    <section 
      id="home"
      ref={sectionRef}
      className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-100 via-white to-emerald-100 dark:from-indigo-900/20 dark:via-dark-bg dark:to-emerald-900/20 bg-fixed"
