            Hi, I’m <span className="text-primary dark:text-primary-light">Mohd Maaz</span>
          </h1>
          <h2 className="text-2xl md:text-4xl font-semibold text-light-text dark:text-dark-text mb-4">
            Machine Learning & MLOps Enthusiast
          </h2>
          <div className="h-10 md:h-12">
            <p className="text-xl md:text-2xl font-mono text-accent dark:text-accent-light">
              <span className="border-r-2 border-accent dark:border-accent-light pr-1">{typedSubheading}</span>
            </p>
          </div>
