interface AboutProps {
    onSecretTrigger?: () => void;
}

const About: React.FC<AboutProps> = ({ onSecretTrigger }) => {
  const profileImageUrl = "data:image/png;base64,";

  const [clickCount, setClickCount] = useState(0);
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const handleImageClick = () => {
    // Clear existing timeout to reset the resetter
    if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
    }

    setClickCount((prev) => {
        const newCount = prev + 1;
        if (newCount >= 5) {
            if (onSecretTrigger) onSecretTrigger();
            return 0; // Reset after trigger
        }
        return newCount;
    });

    // Reset count if no click happens within 1 second
    timeoutRef.current = setTimeout(() => {
        setClickCount(0);
    }, 1000);
  };

  return (
    <section id="about" className="py-20 bg-light-bg dark:bg-dark-bg animate-fade-in-up">
      <div className="container mx-auto px-6">
        <h2 className="text-3xl md:text-4xl font-bold text-center mb-12">
          About Me
        </h2>
        <div className="flex flex-col md:flex-row items-center gap-12">
