import React from 'react';
import { useState } from 'react';
import type { Theme, Page } from '../App';

interface HeaderProps {
  theme: Theme;
  toggleTheme: () => void;
  currentPage: Page;
}

const SunIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364 6.364l-.707-.707M6.343 6.343l-.707-.707m12.728 0l-.707.707M6.343 17.657l-.707.707M16 12a4 4 0 11-8 0 4 4 0 018 0z" />
  </svg>
);

const MoonIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" />
  </svg>
);


const Header: React.FC<HeaderProps> = ({ theme, toggleTheme, currentPage }) => {
  const [isOpen, setIsOpen] = useState(false);

  const navLinks = [
    { href: '#home', label: 'Home', page: 'home' as Page },
    { href: '#about', label: 'About', page: 'about' as Page },
    { href: '#testimonials', label: 'Testimonials', page: 'testimonials' as Page },
    { href: '#projects', label: 'Projects', page: 'projects' as Page },
    { href: '#blog', label: 'Blog', page: 'blog' as Page },
    { href: '#certificates', label: 'Certificates', page: 'certificates' as Page },
    { href: '#contact', label: 'Contact', page: 'contact' as Page },
  ];

  const handleNavClick = (e: React.MouseEvent<HTMLAnchorElement>, page: Page) => {
    e.preventDefault();
    window.location.hash = page;
    if (isOpen) {
      setIsOpen(false);
    }
  };

  return (
    <header className="fixed top-0 left-0 right-0 z-50 bg-light-card/80 dark:bg-dark-card/80 backdrop-blur-sm shadow-md">
      <nav className="container mx-auto px-6 py-4 flex justify-between items-center">
        <a href="#home" onClick={(e) => handleNavClick(e, 'home')} className="text-2xl font-bold text-primary dark:text-primary-light">Mohd Maaz</a>

        <div className="hidden md:flex items-center space-x-8">
          {navLinks.map(link => (
            <a 
              key={link.href} 
              href={link.href} 
              onClick={(e) => handleNavClick(e, link.page)}
              className={`font-medium transition-colors duration-200 ${
                currentPage === link.page 
                ? 'text-primary dark:text-primary-light' 
                : 'text-light-text dark:text-dark-text hover:text-primary dark:hover:text-primary-light'
              }`}
            >
              {link.label}
            </a>
          ))}
          <button onClick={toggleTheme} className="p-2 rounded-full focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary dark:focus:ring-offset-dark-bg">
            {theme === 'light' ? <MoonIcon className="w-6 h-6" /> : <SunIcon className="w-6 h-6" />}
          </button>
        </div>

        <div className="md:hidden flex items-center">
            <button onClick={toggleTheme} className="p-2 mr-2 rounded-full focus:outline-none">
                {theme === 'light' ? <MoonIcon className="w-6 h-6" /> : <SunIcon className="w-6 h-6" />}
            </button>
            <button onClick={() => setIsOpen(!isOpen)} className="text-light-text dark:text-dark-text focus:outline-none">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={isOpen ? "M6 18L18 6M6 6l12 12" : "M4 6h16M4 12h16m-7 6h7"}></path>
                </svg>
            </button>
        </div>
      </nav>
      {isOpen && (
         <div className="md:hidden bg-light-card dark:bg-dark-card">
            <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3 flex flex-col items-center">
                {navLinks.map(link => (
                    <a 
                      key={link.href} 
                      href={link.href} 
                      onClick={(e) => handleNavClick(e, link.page)}
                      className={`block w-full text-center px-3 py-2 rounded-md text-base font-medium ${
                        currentPage === link.page
                        ? 'bg-primary/10 text-primary dark:text-primary-light'
                        : 'text-light-text dark:text-dark-text hover:bg-gray-200 dark:hover:bg-gray-700'
                      }`}
                    >
                        {link.label}
                    </a>
                ))}
            </div>
        </div>
      )}
    </header>
  );
};

export default Header;

import React, { useState, useRef } from 'react';
import { Testimonial } from '../types';

interface TestimonialsProps {
  testimonials: Testimonial[];
  onAddTestimonial: (t: Omit<Testimonial, 'id' | 'status' | 'date'>) => void;
}

const UserIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-gray-400" viewBox="0 0 20 20" fill="currentColor">
    <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
  </svg>
);

const Testimonials: React.FC<TestimonialsProps> = ({ testimonials, onAddTestimonial }) => {
  const [formData, setFormData] = useState({
    name: '',
    designation: '',
    workArea: '',
    feedback: '',
    image: '',
  });
  const [isSubmitted, setIsSubmitted] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const approvedTestimonials = testimonials.filter(t => t.status === 'approved');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.feedback) return;

    onAddTestimonial(formData);

    setFormData({ name: '', designation: '', workArea: '', feedback: '', image: '' });
    if (fileInputRef.current) fileInputRef.current.value = '';

    setIsSubmitted(true);
    setTimeout(() => setIsSubmitted(false), 5000);
  };

  return (
    <section id="testimonials" className="py-20 bg-gray-50 dark:bg-dark-bg/50 animate-fade-in-up">
      <div className="container mx-auto px-6">
        <h2 className="text-3xl md:text-4xl font-bold text-center mb-4">What People Say</h2>
        <p className="text-center text-gray-600 dark:text-gray-400 mb-12 max-w-2xl mx-auto">
          Feedback from clients and colleagues I've had the pleasure of working with.
        </p>

        {/* Display Section */}
        {approvedTestimonials.length > 0 ? (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-20">
            {approvedTestimonials.map((item) => (
              <div key={item.id} className="bg-light-card dark:bg-dark-card p-6 rounded-xl shadow-lg border border-gray-100 dark:border-gray-800 flex flex-col">
                <div className="flex items-center gap-4 mb-4">
                  <div className="w-14 h-14 rounded-full overflow-hidden bg-gray-200 dark:bg-gray-700 flex items-center justify-center flex-shrink-0">
                    {item.image ? (
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                    ) : (
                      <UserIcon />
                    )}
                  </div>
                  <div>
                    <h4 className="font-bold text-lg text-gray-900 dark:text-white">{item.name}</h4>
                    {item.designation && <p className="text-xs text-primary dark:text-primary-light font-semibold uppercase">{item.designation}</p>}
                    {item.workArea && <p className="text-xs text-gray-500 dark:text-gray-400">{item.workArea}</p>}
                  </div>
                </div>

                <div className="relative">
                   <svg className="absolute -top-2 -left-2 w-8 h-8 text-gray-200 dark:text-gray-700 transform -scale-x-100" fill="currentColor" viewBox="0 0 32 32" aria-hidden="true">
                     <path d="M9.352 4C4.456 7.456 1 13.12 1 19.36c0 5.088 3.072 8.064 6.624 8.064 3.36 0 5.856-2.688 5.856-5.856 0-3.168-2.208-5.472-5.088-5.472-.576 0-1.344.096-1.536.192.48-3.264 3.552-7.104 6.624-9.024L9.352 4zm16.512 0c-4.8 3.456-8.256 9.12-8.256 15.36 0 5.088 3.072 8.064 6.624 8.064 3.264 0 5.856-2.688 5.856-5.856 0-3.168-2.304-5.472-5.184-5.472-.576 0-1.248.096-1.44.192.48-3.264 3.456-7.104 6.528-9.024L25.864 4z" />
                   </svg>
                   <p className="text-gray-700 dark:text-gray-300 italic relative z-10 pl-6 text-sm leading-relaxed">
                     "{item.feedback}"
                   </p>
                </div>
              </div>
            ))}
          </div>
        ) : (
            <div className="text-center text-gray-500 py-10 mb-12 bg-light-card dark:bg-dark-card rounded-xl">
                No approved testimonials yet. Be the first to share your feedback!
            </div>
        )}

        {/* Feedback Form Section */}
        <div className="max-w-3xl mx-auto bg-white dark:bg-dark-card rounded-2xl shadow-xl overflow-hidden">
          <div className="md:flex">
             <div className="md:w-1/3 bg-primary dark:bg-primary-dark p-8 text-white flex flex-col justify-center">
                <h3 className="text-2xl font-bold mb-4">Share Your Feedback</h3>
                <p className="mb-6 text-white/80">Your feedback helps build trust. All submissions are reviewed before being published.</p>
                <div className="mt-auto">
                    <p className="text-sm font-semibold opacity-70">Note:</p>
                    <p className="text-xs opacity-70">Submitted feedback will have a 'Pending' status until approved by the admin.</p>
                </div>
             </div>

             <div className="md:w-2/3 p-8">
                {isSubmitted ? (
                  <div className="h-full flex flex-col items-center justify-center text-center py-10">
                    <div className="w-16 h-16 bg-green-100 text-green-500 rounded-full flex items-center justify-center mb-4">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                         <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                       </svg>
                    </div>
                    <h4 className="text-xl font-bold text-gray-900 dark:text-white mb-2">Thank you!</h4>
                    <p className="text-gray-600 dark:text-gray-400">Your feedback has been submitted successfully. It will be reviewed before publishing.</p>
                    <button 
                        onClick={() => setIsSubmitted(false)}
                        className="mt-6 text-primary dark:text-primary-light font-semibold hover:underline"
                    >
                        Submit another
                    </button>
                  </div>
                ) : (
                  <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Name <span className="text-red-500">*</span></label>
                      <input 
                        type="text" 
                        name="name" 
                        value={formData.name} 
                        onChange={handleChange} 
                        required 
                        className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-800 focus:ring-2 focus:ring-primary outline-none" 
                        placeholder="John Doe"
                      />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Designation</label>
                          <input 
                            type="text" 
                            name="designation" 
                            value={formData.designation} 
                            onChange={handleChange} 
                            className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-800 focus:ring-2 focus:ring-primary outline-none" 
                            placeholder="e.g. CEO, Developer"
                          />
                        </div>
                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Work Area</label>
                          <input 
                            type="text" 
                            name="workArea" 
                            value={formData.workArea} 
                            onChange={handleChange} 
                            className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-800 focus:ring-2 focus:ring-primary outline-none" 
