                     </div>
                )}

                {/* BLOG TAB */}
                {activeTab === 'blog' && (
                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg h-fit">
                            <h3 className="text-xl font-bold mb-4">Add Blog Post</h3>
                            <form onSubmit={handleAddBlog} className="space-y-4">
                                <input type="text" placeholder="Title" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={blogForm.title} onChange={e => setBlogForm({...blogForm, title: e.target.value})} />
                                <textarea placeholder="Description" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={blogForm.description} onChange={e => setBlogForm({...blogForm, description: e.target.value})} />
                                <select className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={blogForm.platform} onChange={e => setBlogForm({...blogForm, platform: e.target.value as BlogPlatform})}>
                                    {Object.values(BlogPlatform).map(p => <option key={p} value={p}>{p}</option>)}
                                </select>
                                <input type="url" placeholder="Post URL" required className="w-full p-2 border rounded dark:bg-gray-700 dark:border-gray-600" value={blogForm.url} onChange={e => setBlogForm({...blogForm, url: e.target.value})} />
                                <div>
                                    <label className="block text-sm text-gray-600 dark:text-gray-400 mb-1">Blog Image (Optional)</label>
                                    <input 
                                        type="file" 
                                        ref={blogFileRef}
                                        accept="image/*" 
                                        onChange={(e) => handleImageUpload(e, setBlogForm, blogForm)} 
                                        className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-primary/10 file:text-primary hover:file:bg-primary/20"
                                    />
                                    {blogForm.image && <img src={blogForm.image} alt="Preview" className="mt-2 h-20 w-auto rounded border" />}
                                </div>
                                <button type="submit" className="w-full bg-primary text-white py-2 rounded hover:bg-primary-dark">Add Post</button>
                            </form>
                        </div>
                        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg">
                             <h3 className="text-xl font-bold mb-4">Existing Posts</h3>
                             <div className="space-y-4 max-h-[600px] overflow-y-auto">
                                {blogPosts.map(b => (
                                    <div key={b.id} className="flex justify-between items-center border-b dark:border-gray-700 pb-2">
                                        <div className="flex items-center gap-3">
                                            {b.image && <img src={b.image} alt={b.title} className="w-12 h-12 object-cover rounded" />}
                                            <div>
                                                <p className="font-bold">{b.title}</p>
                                                <p className="text-xs text-gray-500">{b.platform}</p>
                                            </div>
                                        </div>
                                        <button onClick={() => onDeleteBlogPost(b.id)} className="text-red-500 hover:text-red-700 text-sm">Delete</button>
                                    </div>
                                ))}
                             </div>
                        </div>
                     </div>
                )}

                {/* TESTIMONIALS TAB */}
                {activeTab === 'testimonials' && (
                    <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-lg w-full">
                        <h3 className="text-xl font-bold mb-6">Manage Feedback</h3>

                        {/* Summary Counts */}
                        <div className="flex gap-4 mb-6">
                            <div className="px-4 py-2 bg-yellow-100 text-yellow-800 rounded-lg">
                                Pending: {testimonials.filter(t => t.status === 'pending').length}
                            </div>
                             <div className="px-4 py-2 bg-green-100 text-green-800 rounded-lg">
                                Approved: {testimonials.filter(t => t.status === 'approved').length}
                            </div>
                        </div>

                        <div className="overflow-x-auto">
                            <table className="w-full text-left border-collapse">
                                <thead>
                                    <tr className="border-b dark:border-gray-700 text-sm text-gray-500 dark:text-gray-400 uppercase">
                                        <th className="py-3 px-2">Name</th>
                                        <th className="py-3 px-2">Feedback</th>
                                        <th className="py-3 px-2">Status</th>
                                        <th className="py-3 px-2 text-right">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="text-sm">
                                    {testimonials.sort((a,b) => (a.status === 'pending' ? -1 : 1)).map(t => (
                                        <tr key={t.id} className="border-b dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-800/50">
                                            <td className="py-4 px-2">
                                                <p className="font-bold">{t.name}</p>
                                                <p className="text-xs text-gray-500">{t.designation || '-'} {t.workArea ? `at ${t.workArea}` : ''}</p>
                                                <p className="text-xs text-gray-400">{t.date}</p>
                                            </td>
                                            <td className="py-4 px-2 max-w-md">
                                                <p className="line-clamp-2" title={t.feedback}>{t.feedback}</p>
                                            </td>
                                            <td className="py-4 px-2">
                                                <span className={`px-2 py-1 rounded text-xs font-semibold ${
                                                    t.status === 'approved' ? 'bg-green-100 text-green-800' :
                                                    t.status === 'rejected' ? 'bg-red-100 text-red-800' :
                                                    'bg-yellow-100 text-yellow-800'
                                                }`}>
                                                    {t.status.toUpperCase()}
                                                </span>
                                            </td>
                                            <td className="py-4 px-2 text-right space-x-2">
                                                {t.status === 'pending' && (
                                                    <>
                                                        <button 
                                                            onClick={() => onUpdateTestimonialStatus(t.id, 'approved')}
                                                            className="text-green-600 hover:text-green-800 font-medium"
                                                        >
                                                            Approve
                                                        </button>
                                                        <button 
                                                            onClick={() => onUpdateTestimonialStatus(t.id, 'rejected')}
                                                            className="text-red-500 hover:text-red-700 font-medium"
                                                        >
                                                            Reject
                                                        </button>
                                                    </>
                                                )}
                                                {t.status !== 'pending' && t.status !== 'approved' && (
                                                    <button 
                                                        onClick={() => onUpdateTestimonialStatus(t.id, 'approved')}
                                                        className="text-green-600 hover:text-green-800 font-medium"
                                                    >
                                                        Approve
                                                    </button>
                                                )}
                                                 {t.status === 'approved' && (
                                                    <button 
                                                        onClick={() => onUpdateTestimonialStatus(t.id, 'pending')}
                                                        className="text-yellow-600 hover:text-yellow-800 font-medium"
                                                    >
                                                        Unpublish
                                                    </button>
                                                )}
                                                <button 
                                                    onClick={() => onDeleteTestimonial(t.id)}
                                                    className="text-gray-400 hover:text-red-500 ml-2"
                                                    title="Delete permanently"
                                                >
                                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                                    </svg>
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                    {testimonials.length === 0 && (
                                        <tr>
                                            <td colSpan={4} className="py-8 text-center text-gray-500">No testimonials submitted yet.</td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </div>
        </section>
    );
};

export default AdminPanel;

import React from 'react';
import { useState, useEffect } from 'react';
import Header from './components/Header';
import Home from './components/Home';
import About from './components/About';
import Projects from './components/Projects';
import Blog from './components/Blog';
import Contact from './components/Contact';
import Certificates from './components/Certificates';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import Testimonials from './components/Testimonials';
import { PROJECTS as INITIAL_PROJECTS, CERTIFICATES as INITIAL_CERTIFICATES, BLOG_POSTS as INITIAL_BLOG_POSTS, INITIAL_TESTIMONIALS } from './constants';
import { Project, Certificate, BlogPost, Testimonial, TestimonialStatus } from './types';

export type Theme = 'light' | 'dark';
export type Page = 'home' | 'about' | 'projects' | 'certificates' | 'blog' | 'contact' | 'admin' | 'testimonials';

const Footer: React.FC = () => {
  const currentYear = new Date().getFullYear();
  return (
    <footer className="bg-light-card dark:bg-dark-card/50">
       <div className="container mx-auto px-6 py-6 text-center border-t border-gray-200 dark:border-gray-700">
          <p className="text-gray-500 dark:text-gray-400">
            &copy; {currentYear} Mohd Maaz. All Rights Reserved.
          </p>
        </div>
    </footer>
  );
};

const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('light');
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);

  // DATA STATE with LocalStorage Persistence
  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('portfolio_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });

  const [certificates, setCertificates] = useState<Certificate[]>(() => {
    const saved = localStorage.getItem('portfolio_certificates');
    return saved ? JSON.parse(saved) : INITIAL_CERTIFICATES;
  });

  const [blogPosts, setBlogPosts] = useState<BlogPost[]>(() => {
    const saved = localStorage.getItem('portfolio_blogs');
    return saved ? JSON.parse(saved) : INITIAL_BLOG_POSTS;
  });

  const [testimonials, setTestimonials] = useState<Testimonial[]>(() => {
    const saved = localStorage.getItem('portfolio_testimonials');
    return saved ? JSON.parse(saved) : INITIAL_TESTIMONIALS;
  });

  // Persist Data changes
  useEffect(() => { localStorage.setItem('portfolio_projects', JSON.stringify(projects)); }, [projects]);
  useEffect(() => { localStorage.setItem('portfolio_certificates', JSON.stringify(certificates)); }, [certificates]);
  useEffect(() => { localStorage.setItem('portfolio_blogs', JSON.stringify(blogPosts)); }, [blogPosts]);
  useEffect(() => { localStorage.setItem('portfolio_testimonials', JSON.stringify(testimonials)); }, [testimonials]);

  // CRUD OPERATIONS
  const addProject = (project: Omit<Project, 'id'>) => {
    const newProject = { ...project, id: Date.now().toString() };
    setProjects([newProject, ...projects]);
  };
  const deleteProject = (id: string) => setProjects(projects.filter(p => p.id !== id));

  const addCertificate = (cert: Omit<Certificate, 'id'>) => {
    const newCert = { ...cert, id: Date.now().toString() };
    setCertificates([newCert, ...certificates]);
  };
  const deleteCertificate = (id: string) => setCertificates(certificates.filter(c => c.id !== id));

  const addBlogPost = (post: Omit<BlogPost, 'id'>) => {
    const newPost = { ...post, id: Date.now().toString() };
    setBlogPosts([newPost, ...blogPosts]);
  };
  const deleteBlogPost = (id: string) => setBlogPosts(blogPosts.filter(b => b.id !== id));

  // Testimonial Operations
  const addTestimonial = (testimonial: Omit<Testimonial, 'id' | 'status' | 'date'>) => {
      const newTestimonial: Testimonial = {
          ...testimonial,
          id: Date.now().toString(),
          status: 'pending', // Default status
          date: new Date().toISOString().split('T')[0]
      };
      // Add to beginning of list
      setTestimonials([newTestimonial, ...testimonials]);
  };

  const updateTestimonialStatus = (id: string, status: TestimonialStatus) => {
      setTestimonials(testimonials.map(t => t.id === id ? { ...t, status } : t));
  };

  const deleteTestimonial = (id: string) => {
      setTestimonials(testimonials.filter(t => t.id !== id));
  };


  // Theme & Navigation Logic
  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as Theme | null;
    const prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
    if (savedTheme) {
      setTheme(savedTheme);
      document.documentElement.classList.toggle('dark', savedTheme === 'dark');
    } else if (prefersDark) {
      setTheme('dark');
      document.documentElement.classList.toggle('dark', true);
    }

    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '') as Page;
      if (hash === 'admin' && !isAdmin) {
          window.location.hash = 'home';
          return;
      }
      if (hash) {
          setCurrentPage(hash);
      }
    };
    window.addEventListener('hashchange', handleHashChange, false);

    const hash = window.location.hash.replace('#', '') as Page;
    if (hash === 'admin' && !isAdmin) {
        window.location.hash = 'home';
    } else if (hash) {
        setCurrentPage(hash);
    }

    return () => {
      window.removeEventListener('hashchange', handleHashChange, false);
    };
  }, [isAdmin]);

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.documentElement.classList.toggle('dark', newTheme === 'dark');
  };

  const handleSecretTrigger = () => {
      if (!isAdmin) {
          setShowLogin(true);
      } else {
          window.location.hash = 'admin';
          setCurrentPage('admin');
      }
  };

  const handleLogin = (code: string) => {
      if (code === '050505') {
          setIsAdmin(true);
          setShowLogin(false);
          window.location.hash = 'admin';
          setCurrentPage('admin');
          return true;
      }
      return false;
  };

  const handleLogout = () => {
      setIsAdmin(false);
      window.location.hash = 'home';
      setCurrentPage('home');
  };

  return (
    <>
      {isAdmin && currentPage === 'admin' ? (
          <AdminPanel 
            onLogout={handleLogout}
            projects={projects}
            certificates={certificates}
            blogPosts={blogPosts}
            testimonials={testimonials}
            onAddProject={addProject}
            onDeleteProject={deleteProject}
            onAddCertificate={addCertificate}
            onDeleteCertificate={deleteCertificate}
            onAddBlogPost={addBlogPost}
            onDeleteBlogPost={deleteBlogPost}
            onUpdateTestimonialStatus={updateTestimonialStatus}
            onDeleteTestimonial={deleteTestimonial}
          />
      ) : (
        <>
          <Header theme={theme} toggleTheme={toggleTheme} currentPage={currentPage} />
          <main>
            <Home />
            <About onSecretTrigger={handleSecretTrigger} />
            <Testimonials testimonials={testimonials} onAddTestimonial={addTestimonial} />
            <Projects projects={projects} />
            <Blog posts={blogPosts} />
            <Certificates certificates={certificates} />
            <Contact />
          </main>
          <Footer />
        </>
      )}

      <AdminLogin 
        isOpen={showLogin} 
        onClose={() => setShowLogin(false)} 
        onLogin={handleLogin} 
      />
    </>
  );
};

export default App;

