const Contact: React.FC = () => {
  const [formData, setFormData] = useState({ name: '', email: '', message: '' });
  const [isSending, setIsSending] = useState(false);
  const [isSent, setIsSent] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.message) {
      setError("Please fill out all fields.");
      return;
    }
    setError('');
    setIsSending(true);

    // --- IMPORTANT ---
    // Replace these with your actual EmailJS credentials
    const serviceID = 'YOUR_SERVICE_ID';
    const templateID = 'YOUR_TEMPLATE_ID';
    const publicKey = 'YOUR_PUBLIC_KEY';

    const templateParams = {
        name: formData.name,
        email: formData.email,
        message: formData.message,
    };

    window.emailjs.send(serviceID, templateID, templateParams, publicKey)
      .then((response: any) => {
        console.log('SUCCESS!', response.status, response.text);
        setIsSending(false);
        setIsSent(true);
        setFormData({ name: '', email: '', message: '' });
        setTimeout(() => setIsSent(false), 5000); // Reset message after 5 seconds
      }, (err: any) => {
        console.log('FAILED...', err);
        setIsSending(false);
        setError('Failed to send message. Please try again later.');
      });
  };


  return (
    <section id="contact" className="py-20 animate-fade-in-up">
      <div className="container mx-auto px-6">
        <h2 className="text-3xl md:text-4xl font-bold text-center mb-12 text-gray-900 dark:text-white">
          Contact Me
        </h2>
        <div className="flex flex-col md:flex-row gap-12 lg:gap-16">

          {/* Left Column: Contact Info */}
          <div className="md:w-1/2">
            <h3 className="text-2xl font-bold mb-4 text-gray-900 dark:text-white">Get In Touch</h3>
            <p className="text-gray-700 dark:text-gray-300 mb-6 font-medium">
              I'm actively looking for new opportunities and love to connect with fellow professionals. Whether you have a question, a project proposal, or just want to say hi, feel free to reach out through any of these platforms or by using the contact form.
            </p>
            <div className="space-y-4">
              {contactLinks.map(({ href, icon: Icon, label }) => (
                <a 
                  key={label}
                  href={href}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex items-center p-4 rounded-xl group bg-white/50 dark:bg-gray-800/50 backdrop-blur-sm border border-white/40 dark:border-gray-700 text-gray-700 dark:text-gray-300 hover:bg-white dark:hover:bg-gray-800 hover:shadow-md transition-all duration-300"
                >
                  <div className="p-2 rounded-full bg-white dark:bg-gray-700 text-gray-600 dark:text-gray-300 group-hover:text-primary dark:group-hover:text-primary-light transition-colors">
                     <Icon />
                  </div>
                  <span className="ml-4 font-bold group-hover:text-primary dark:group-hover:text-primary-light">{label}</span>
                </a>
              ))}
            </div>
          </div>

          {/* Right Column: Contact Form */}
          <div className="md:w-1/2">
             <div className="bg-white/70 dark:bg-gray-800/60 backdrop-blur-md p-8 rounded-2xl shadow-xl border border-white/40 dark:border-gray-700">
                <h3 className="text-2xl font-bold mb-6 text-gray-900 dark:text-white">Send me a Message</h3>
                {isSent ? (
                  <div className="text-center p-4 bg-accent/10 border border-accent/20 text-accent-dark dark:text-accent-light rounded-xl">
                    <h4 className="font-bold">Thank you!</h4>
                    <p>Your message has been sent successfully.</p>
                  </div>
                ) : (
                  <form onSubmit={handleSubmit}>
                    <div className="mb-4">
                      <label htmlFor="name" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Full Name</label>
                      <input type="text" name="name" id="name" value={formData.name} onChange={handleChange} className="w-full px-4 py-3 bg-white/50 dark:bg-gray-900/50 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary transition-all" required />
                    </div>
                     <div className="mb-4">
                      <label htmlFor="email" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Email Address</label>
                      <input type="email" name="email" id="email" value={formData.email} onChange={handleChange} className="w-full px-4 py-3 bg-white/50 dark:bg-gray-900/50 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary transition-all" required />
                    </div>
                     <div className="mb-6">
                      <label htmlFor="message" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Message</label>
                      <textarea name="message" id="message" rows={4} value={formData.message} onChange={handleChange} className="w-full px-4 py-3 bg-white/50 dark:bg-gray-900/50 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary transition-all" required></textarea>
                    </div>
                    {error && <p className="text-red-500 text-sm mb-4">{error}</p>}
                    <button 
                      type="submit" 
                      disabled={isSending}
                      className="w-full px-6 py-3 bg-primary text-white font-bold rounded-lg shadow-md hover:bg-primary-dark dark:hover:bg-primary-light transform hover:scale-105 transition-all duration-300 disabled:bg-gray-400 disabled:scale-100"
                    >
                      {isSending ? 'Sending...' : 'Send Message'}
                    </button>
                  </form>
                )}
             </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Contact;

import React, { useState, useRef } from 'react';
import { Testimonial } from '../types';

interface TestimonialsProps {
  testimonials: Testimonial[];
  onAddTestimonial: (t: Omit<Testimonial, 'id' | 'status' | 'date'>) => void;
}

const UserIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-gray-400" viewBox="0 0 20 20" fill="currentColor">
    <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
  </svg>
);

const Testimonials: React.FC<TestimonialsProps> = ({ testimonials, onAddTestimonial }) => {
  const [formData, setFormData] = useState({
    name: '',
    designation: '',
    workArea: '',
    feedback: '',
    image: '',
  });
  const [isSubmitted, setIsSubmitted] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const approvedTestimonials = testimonials.filter(t => t.status === 'approved');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.feedback) return;

    onAddTestimonial(formData);

    setFormData({ name: '', designation: '', workArea: '', feedback: '', image: '' });
    if (fileInputRef.current) fileInputRef.current.value = '';

    setIsSubmitted(true);
    setTimeout(() => setIsSubmitted(false), 5000);
  };

  return (
    <section id="testimonials" className="py-20 animate-fade-in-up">
      <div className="container mx-auto px-6">
        <h2 className="text-3xl md:text-4xl font-bold text-center mb-4 text-gray-900 dark:text-white">What People Say</h2>
        <p className="text-center text-gray-600 dark:text-gray-400 mb-12 max-w-2xl mx-auto">
          Feedback from clients and colleagues I've had the pleasure of working with.
        </p>

        {/* Display Section */}
        {approvedTestimonials.length > 0 ? (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-20">
            {approvedTestimonials.map((item) => (
              <div key={item.id} className="bg-white/70 dark:bg-gray-800/60 backdrop-blur-sm p-6 rounded-xl shadow-lg border border-white/40 dark:border-gray-700 flex flex-col hover:-translate-y-1 transition-transform duration-300">
                <div className="flex items-center gap-4 mb-4">
                  <div className="w-14 h-14 rounded-full overflow-hidden bg-gray-200 dark:bg-gray-700 flex items-center justify-center flex-shrink-0 border border-white/50 dark:border-gray-600">
                    {item.image ? (
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                    ) : (
                      <UserIcon />
                    )}
                  </div>
                  <div>
                    <h4 className="font-bold text-lg text-gray-900 dark:text-white">{item.name}</h4>
                    {item.designation && <p className="text-xs text-primary dark:text-primary-light font-semibold uppercase">{item.designation}</p>}
                    {item.workArea && <p className="text-xs text-gray-500 dark:text-gray-400">{item.workArea}</p>}
                  </div>
                </div>

                <div className="relative">
                   <svg className="absolute -top-2 -left-2 w-8 h-8 text-gray-300 dark:text-gray-600 transform -scale-x-100 opacity-50" fill="currentColor" viewBox="0 0 32 32" aria-hidden="true">
                     <path d="M9.352 4C4.456 7.456 1 13.12 1 19.36c0 5.088 3.072 8.064 6.624 8.064 3.36 0 5.856-2.688 5.856-5.856 0-3.168-2.208-5.472-5.088-5.472-.576 0-1.344.096-1.536.192.48-3.264 3.552-7.104 6.624-9.024L9.352 4zm16.512 0c-4.8 3.456-8.256 9.12-8.256 15.36 0 5.088 3.072 8.064 6.624 8.064 3.264 0 5.856-2.688 5.856-5.856 0-3.168-2.304-5.472-5.184-5.472-.576 0-1.248.096-1.44.192.48-3.264 3.456-7.104 6.528-9.024L25.864 4z" />
                   </svg>
                   <p className="text-gray-700 dark:text-gray-300 italic relative z-10 pl-6 text-sm leading-relaxed">
                     "{item.feedback}"
                   </p>
                </div>
              </div>
            ))}
          </div>
        ) : (
            <div className="text-center text-gray-500 py-10 mb-12 bg-white/50 dark:bg-gray-800/50 backdrop-blur-sm rounded-xl border border-dashed border-gray-300 dark:border-gray-700">
                No approved testimonials yet. Be the first to share your feedback!
            </div>
        )}

        {/* Feedback Form Section */}
        <div className="max-w-3xl mx-auto bg-white/80 dark:bg-gray-800/80 backdrop-blur-md rounded-2xl shadow-xl overflow-hidden border border-white/20 dark:border-gray-700">
          <div className="md:flex">
             <div className="md:w-1/3 bg-primary/90 dark:bg-primary-dark/90 p-8 text-white flex flex-col justify-center backdrop-blur-sm">
                <h3 className="text-2xl font-bold mb-4">Share Your Feedback</h3>
                <p className="mb-6 text-white/80">Your feedback helps build trust. All submissions are reviewed before being published.</p>
                <div className="mt-auto">
                    <p className="text-sm font-semibold opacity-70">Note:</p>
                    <p className="text-xs opacity-70">Submitted feedback will have a 'Pending' status until approved by the admin.</p>
                </div>
             </div>

             <div className="md:w-2/3 p-8">
                {isSubmitted ? (
                  <div className="h-full flex flex-col items-center justify-center text-center py-10">
                    <div className="w-16 h-16 bg-green-100 text-green-500 rounded-full flex items-center justify-center mb-4">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                         <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                       </svg>
                    </div>
                    <h4 className="text-xl font-bold text-gray-900 dark:text-white mb-2">Thank you!</h4>
                    <p className="text-gray-600 dark:text-gray-400">Your feedback has been submitted successfully. It will be reviewed before publishing.</p>
                    <button 
                        onClick={() => setIsSubmitted(false)}
                        className="mt-6 text-primary dark:text-primary-light font-semibold hover:underline"
                    >
                        Submit another
                    </button>
                  </div>
                ) : (
                  <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Name <span className="text-red-500">*</span></label>
                      <input 
                        type="text" 
                        name="name" 
                        value={formData.name} 
                        onChange={handleChange} 
                        required 
                        className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white/50 dark:bg-gray-900/50 focus:ring-2 focus:ring-primary outline-none" 
                        placeholder="John Doe"
                      />
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Designation</label>
                          <input 
                            type="text" 
                            name="designation" 
                            value={formData.designation} 
                            onChange={handleChange} 
                            className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white/50 dark:bg-gray-900/50 focus:ring-2 focus:ring-primary outline-none" 
                            placeholder="e.g. CEO, Developer"
                          />
                        </div>
                        <div>
                          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Work Area</label>
                          <input 
                            type="text" 
                            name="workArea" 
                            value={formData.workArea} 
                            onChange={handleChange} 
                            className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white/50 dark:bg-gray-900/50 focus:ring-2 focus:ring-primary outline-none" 
                            placeholder="e.g. Data Science"
                          />
                        </div>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Feedback <span className="text-red-500">*</span></label>
                      <textarea 
                        name="feedback" 
                        value={formData.feedback} 
                        onChange={handleChange} 
                        required 
                        rows={4}
                        className="w-full px-4 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white/50 dark:bg-gray-900/50 focus:ring-2 focus:ring-primary outline-none" 
                        placeholder="Share your experience working with me..."
                      ></textarea>
                    </div>

                    <div>
                       <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Your Photo (Optional)</label>
                       <input 
                           type="file" 
                           ref={fileInputRef}
                           accept="image/*" 
                           onChange={handleImageUpload}
                           className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-primary/10 file:text-primary hover:file:bg-primary/20"
                       />
                    </div>

                    <div className="pt-2">
                        <button type="submit" className="w-full bg-gray-900 dark:bg-white dark:text-gray-900 text-white font-bold py-3 rounded-lg shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 transition-all">
                            Submit Feedback
                        </button>
                    </div>
                  </form>
                )}
             </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Testimonials;

