            <a href={project.liveUrl} target="_blank" rel="noopener noreferrer" className="text-gray-500 dark:text-gray-400 hover:text-accent dark:hover:text-accent-light transition-colors">
              <LinkIcon />
            </a>
          )}
        </div>
      </div>
    </div>
  );
};

