            Hi, I’m <span className="text-blue-700 dark:text-blue-400">Mohd Maaz</span>
          </h1>

          <p className="text-base md:text-lg text-gray-700 dark:text-gray-300 font-medium mb-6 tracking-wide">
            🏅 University Gold Medalist | MCA | BCA
          </p>

          <h2 className="text-2xl md:text-3xl font-medium text-gray-600 dark:text-gray-300 mb-8">
            Machine Learning Engineer focused on <span className="text-gray-900 dark:text-white font-semibold">MLOps & GenAI</span>
          </h2>

          {/* Typewriter Container */}
          <div className="h-16 flex items-center justify-center">
            <p className="text-xl md:text-3xl font-bold font-mono text-accent dark:text-accent-light inline-flex items-center">
              <span>{subheading}</span>
              <span className="ml-1 w-1 h-8 bg-accent dark:bg-accent-light animate-pulse"></span>
