        {/* Feedback Form Section */}
        <div className="max-w-4xl mx-auto bg-white/70 dark:bg-gray-800/60 backdrop-blur-md rounded-2xl shadow-2xl overflow-hidden border border-white/40 dark:border-gray-700">
          <div className="md:flex h-full">
             {/* Info Side */}
             <div className="md:w-5/12 bg-gradient-to-br from-primary to-primary-dark p-8 text-white flex flex-col justify-between relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-2xl transform translate-x-10 -translate-y-10"></div>
                <div className="absolute bottom-0 left-0 w-32 h-32 bg-black/10 rounded-full blur-2xl transform -translate-x-10 translate-y-10"></div>

                <div className="relative z-10">
                    <h3 className="text-3xl font-bold mb-4 leading-tight">Share Your Experience</h3>
                    <p className="text-white/90 leading-relaxed">
                        Your feedback helps me improve and builds trust with future clients.
                    </p>
                </div>

                <div className="relative z-10 mt-8">
                    <div className="flex items-start gap-3 bg-white/10 p-4 rounded-xl backdrop-blur-sm">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-accent-light mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
