                </div>
             </div>

             {/* Form Side */}
             <div className="md:w-7/12 p-8 md:p-10">
                {isSubmitted ? (
                  <div className="h-full flex flex-col items-center justify-center text-center py-10 min-h-[300px]">
                    <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 text-green-500 rounded-full flex items-center justify-center mb-6 shadow-sm">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
