                    <h4 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">Thank you!</h4>
                    <p className="text-gray-600 dark:text-gray-400 mb-8 max-w-xs mx-auto">Your feedback has been submitted successfully.</p>
