                  </div>
                ) : (
                  <form onSubmit={handleSubmit} className="space-y-5">
                    <div>
                      <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Name <span className="text-red-500">*</span></label>
                      <input 
                        type="text" 
                        name="name" 
                        value={formData.name} 
                        onChange={handleChange} 
                        required 
                        className="w-full px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl bg-white/50 dark:bg-gray-900/50 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all placeholder-gray-400 dark:placeholder-gray-600" 
                        placeholder="Your Name"
                      />
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                        <div>
                          <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Designation</label>
                          <input 
                            type="text" 
                            name="designation" 
                            value={formData.designation} 
                            onChange={handleChange} 
                            className="w-full px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl bg-white/50 dark:bg-gray-900/50 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all placeholder-gray-400 dark:placeholder-gray-600" 
                            placeholder="e.g. CEO"
                          />
                        </div>
                        <div>
                          <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Company / Area</label>
                          <input 
                            type="text" 
                            name="workArea" 
                            value={formData.workArea} 
                            onChange={handleChange} 
                            className="w-full px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl bg-white/50 dark:bg-gray-900/50 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all placeholder-gray-400 dark:placeholder-gray-600" 
                            placeholder="e.g. Tech Corp"
                          />
                        </div>
                    </div>

                    <div>
                      <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Feedback <span className="text-red-500">*</span></label>
                      <textarea 
                        name="feedback" 
                        value={formData.feedback} 
                        onChange={handleChange} 
                        required 
                        rows={4}
                        className="w-full px-4 py-3 border border-gray-300 dark:border-gray-600 rounded-xl bg-white/50 dark:bg-gray-900/50 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all resize-none placeholder-gray-400 dark:placeholder-gray-600" 
                        placeholder="What was your experience like?"
                      ></textarea>
                    </div>

                    <div>
                       <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Photo (Optional)</label>
                       <div className="flex items-center space-x-4">
