                               <input 
                                   type="file" 
                                   ref={fileInputRef}
                                   accept="image/*" 
                                   onChange={handleImageUpload}
                                   className="w-full text-sm text-gray-500 file:mr-4 file:py-2.5 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-bold file:bg-primary/10 file:text-primary hover:file:bg-primary/20 cursor-pointer"
                               />
                           </div>
                       </div>
                    </div>

                    <div className="pt-2">
                        <button type="submit" className="w-full bg-gray-900 dark:bg-white dark:text-gray-900 text-white font-bold py-3.5 rounded-xl shadow-lg hover:shadow-xl hover:-translate-y-0.5 transition-all duration-200">
                            Submit Feedback
                        </button>
                    </div>
                  </form>
                )}
             </div>
          </div>
        </div>
      </div>
    </section>
  );
};

