import React from 'react';
import { useState, useEffect } from 'react';
import Header from './components/Header';
import Home from './components/Home';
import About from './components/About';
import Projects from './components/Projects';
import Blog from './components/Blog';
import Contact from './components/Contact';
import Certificates from './components/Certificates';
import AdminLogin from './components/AdminLogin';
import AdminPanel from './components/AdminPanel';
import Testimonials from './components/Testimonials';
import { PROJECTS as INITIAL_PROJECTS, CERTIFICATES as INITIAL_CERTIFICATES, BLOG_POSTS as INITIAL_BLOG_POSTS, INITIAL_TESTIMONIALS } from './constants';
import { Project, Certificate, BlogPost, Testimonial, TestimonialStatus } from './types';

export type Theme = 'light' | 'dark';
export type Page = 'home' | 'about' | 'projects' | 'certificates' | 'blog' | 'contact' | 'admin' | 'testimonials';

const Footer: React.FC = () => {
  const currentYear = new Date().getFullYear();
  return (
    <footer className="bg-white/50 dark:bg-gray-900/50 backdrop-blur-md relative z-10 border-t border-gray-200/50 dark:border-gray-700/50">
       <div className="container mx-auto px-6 py-6 text-center">
          <p className="text-gray-500 dark:text-gray-400">
            &copy; {currentYear} Mohd Maaz. All Rights Reserved.
          </p>
        </div>
    </footer>
  );
};

const Background = () => (
  <div className="fixed inset-0 -z-50 overflow-hidden pointer-events-none">
    {/* Global Gradient Background */}
    <div className="absolute inset-0 bg-gradient-to-br from-indigo-50 via-white to-emerald-50 dark:from-indigo-950 dark:via-dark-bg dark:to-emerald-950 transition-colors duration-500"></div>

    {/* Decorative Background Elements (Blobs) */}
    <div className="absolute top-0 left-0 w-[500px] h-[500px] bg-primary/20 rounded-full mix-blend-multiply filter blur-[80px] opacity-40 animate-blob"></div>
    <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-accent/20 rounded-full mix-blend-multiply filter blur-[80px] opacity-40 animate-blob animation-delay-2000"></div>
    <div className="absolute -bottom-32 left-20 w-[600px] h-[600px] bg-purple-300/20 rounded-full mix-blend-multiply filter blur-[80px] opacity-40 animate-blob animation-delay-4000"></div>
    <div className="absolute bottom-0 right-0 w-[400px] h-[400px] bg-yellow-200/20 dark:bg-blue-900/20 rounded-full mix-blend-multiply filter blur-[80px] opacity-40 animate-blob animation-delay-3000"></div>
  </div>
);

const App: React.FC = () => {
  const [theme, setTheme] = useState<Theme>('light');
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [isAdmin, setIsAdmin] = useState(false);
  const [showLogin, setShowLogin] = useState(false);

  // DATA STATE with LocalStorage Persistence
  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('portfolio_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });

  const [certificates, setCertificates] = useState<Certificate[]>(() => {
    const saved = localStorage.getItem('portfolio_certificates');
    return saved ? JSON.parse(saved) : INITIAL_CERTIFICATES;
  });

  const [blogPosts, setBlogPosts] = useState<BlogPost[]>(() => {
    const saved = localStorage.getItem('portfolio_blogs');
    return saved ? JSON.parse(saved) : INITIAL_BLOG_POSTS;
  });

  const [testimonials, setTestimonials] = useState<Testimonial[]>(() => {
    const saved = localStorage.getItem('portfolio_testimonials');
    return saved ? JSON.parse(saved) : INITIAL_TESTIMONIALS;
  });

  // Persist Data changes
  useEffect(() => { localStorage.setItem('portfolio_projects', JSON.stringify(projects)); }, [projects]);
  useEffect(() => { localStorage.setItem('portfolio_certificates', JSON.stringify(certificates)); }, [certificates]);
  useEffect(() => { localStorage.setItem('portfolio_blogs', JSON.stringify(blogPosts)); }, [blogPosts]);
  useEffect(() => { localStorage.setItem('portfolio_testimonials', JSON.stringify(testimonials)); }, [testimonials]);

  // CRUD OPERATIONS
  const addProject = (project: Omit<Project, 'id'>) => {
    const newProject = { ...project, id: Date.now().toString() };
    setProjects([newProject, ...projects]);
  };
  const deleteProject = (id: string) => setProjects(projects.filter(p => p.id !== id));

  const addCertificate = (cert: Omit<Certificate, 'id'>) => {
    const newCert = { ...cert, id: Date.now().toString() };
    setCertificates([newCert, ...certificates]);
  };
  const deleteCertificate = (id: string) => setCertificates(certificates.filter(c => c.id !== id));

  const addBlogPost = (post: Omit<BlogPost, 'id'>) => {
    const newPost = { ...post, id: Date.now().toString() };
    setBlogPosts([newPost, ...blogPosts]);
  };
  const deleteBlogPost = (id: string) => setBlogPosts(blogPosts.filter(b => b.id !== id));

  // Testimonial Operations
  const addTestimonial = (testimonial: Omit<Testimonial, 'id' | 'status' | 'date'>) => {
      const newTestimonial: Testimonial = {
          ...testimonial,
          id: Date.now().toString(),
          status: 'pending', // Default status
          date: new Date().toISOString().split('T')[0]
      };
      // Add to beginning of list
      setTestimonials([newTestimonial, ...testimonials]);
  };

  const updateTestimonialStatus = (id: string, status: TestimonialStatus) => {
      setTestimonials(testimonials.map(t => t.id === id ? { ...t, status } : t));
  };

  const deleteTestimonial = (id: string) => {
      setTestimonials(testimonials.filter(t => t.id !== id));
  };


  // Theme & Navigation Logic
  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as Theme | null;
    const prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
    if (savedTheme) {
      setTheme(savedTheme);
      document.documentElement.classList.toggle('dark', savedTheme === 'dark');
    } else if (prefersDark) {
      setTheme('dark');
      document.documentElement.classList.toggle('dark', true);
    }

    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '') as Page;
      if (hash === 'admin' && !isAdmin) {
          window.location.hash = 'home';
          return;
      }
      if (hash) {
          setCurrentPage(hash);
      }
    };
    window.addEventListener('hashchange', handleHashChange, false);

    const hash = window.location.hash.replace('#', '') as Page;
    if (hash === 'admin' && !isAdmin) {
        window.location.hash = 'home';
    } else if (hash) {
        setCurrentPage(hash);
    }

    return () => {
      window.removeEventListener('hashchange', handleHashChange, false);
    };
  }, [isAdmin]);

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.documentElement.classList.toggle('dark', newTheme === 'dark');
  };

  const handleSecretTrigger = () => {
      if (!isAdmin) {
          setShowLogin(true);
      } else {
          window.location.hash = 'admin';
          setCurrentPage('admin');
      }
  };

  const handleLogin = (code: string) => {
      if (code === '050505') {
          setIsAdmin(true);
          setShowLogin(false);
          window.location.hash = 'admin';
          setCurrentPage('admin');
          return true;
      }
      return false;
  };

  const handleLogout = () => {
      setIsAdmin(false);
      window.location.hash = 'home';
      setCurrentPage('home');
  };

  return (
    <>
      <Background />
      {isAdmin && currentPage === 'admin' ? (
          <AdminPanel 
            onLogout={handleLogout}
            projects={projects}
            certificates={certificates}
            blogPosts={blogPosts}
            testimonials={testimonials}
            onAddProject={addProject}
            onDeleteProject={deleteProject}
            onAddCertificate={addCertificate}
            onDeleteCertificate={deleteCertificate}
            onAddBlogPost={addBlogPost}
            onDeleteBlogPost={deleteBlogPost}
            onUpdateTestimonialStatus={updateTestimonialStatus}
            onDeleteTestimonial={deleteTestimonial}
          />
      ) : (
        <>
          <Header theme={theme} toggleTheme={toggleTheme} currentPage={currentPage} />
          <main className="relative z-10">
            <Home />
            <About onSecretTrigger={handleSecretTrigger} />
            <Testimonials testimonials={testimonials} onAddTestimonial={addTestimonial} />
            <Projects projects={projects} />
            <Blog posts={blogPosts} />
            <Certificates certificates={certificates} />
            <Contact />
          </main>
          <Footer />
        </>
      )}

      <AdminLogin 
        isOpen={showLogin} 
        onClose={() => setShowLogin(false)} 
        onLogin={handleLogin} 
      />
    </>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Testimonial } from '../types';

interface TestimonialsProps {
  testimonials: Testimonial[];
  onAddTestimonial: (t: Omit<Testimonial, 'id' | 'status' | 'date'>) => void;
}

const UserIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-gray-400 dark:text-gray-500" viewBox="0 0 20 20" fill="currentColor">
    <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
  </svg>
);

const Testimonials: React.FC<TestimonialsProps> = ({ testimonials, onAddTestimonial }) => {
  const [formData, setFormData] = useState({
    name: '',
    designation: '',
    workArea: '',
    feedback: '',
    image: '',
  });
  const [isSubmitted, setIsSubmitted] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const approvedTestimonials = testimonials.filter(t => t.status === 'approved');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.feedback) return;

    onAddTestimonial(formData);

    setFormData({ name: '', designation: '', workArea: '', feedback: '', image: '' });
    if (fileInputRef.current) fileInputRef.current.value = '';

    setIsSubmitted(true);
    setTimeout(() => setIsSubmitted(false), 5000);
  };

  return (
    <section id="testimonials" className="py-20 animate-fade-in-up">
      <div className="container mx-auto px-6">
        <h2 className="text-3xl md:text-4xl font-bold text-center mb-4 text-gray-900 dark:text-white">What People Say</h2>
        <p className="text-center text-gray-600 dark:text-gray-400 mb-12 max-w-2xl mx-auto">
          Feedback from clients and colleagues I've had the pleasure of working with.
        </p>

        {/* Display Section */}
        {approvedTestimonials.length > 0 ? (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-20">
            {approvedTestimonials.map((item) => (
              <div key={item.id} className="bg-white/70 dark:bg-gray-800/60 backdrop-blur-sm p-8 rounded-2xl shadow-lg border border-white/40 dark:border-gray-700 flex flex-col hover:-translate-y-2 transition-transform duration-300">
                <div className="flex items-center gap-4 mb-6">
                  <div className="w-14 h-14 rounded-full overflow-hidden bg-gray-200 dark:bg-gray-700 flex items-center justify-center flex-shrink-0 border-2 border-white dark:border-gray-600 shadow-sm">
                    {item.image ? (
                      <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                    ) : (
                      <UserIcon />
                    )}
                  </div>
                  <div>
                    <h4 className="font-bold text-lg text-gray-900 dark:text-white leading-tight">{item.name}</h4>
                    <div className="flex flex-col mt-0.5">
                        {item.designation && <span className="text-xs text-primary dark:text-primary-light font-bold uppercase tracking-wide">{item.designation}</span>}
                        {item.workArea && <span className="text-xs text-gray-500 dark:text-gray-400 font-medium">{item.workArea}</span>}
                    </div>
                  </div>
                </div>

                <div className="relative flex-grow">
                   <svg className="absolute -top-3 -left-2 w-8 h-8 text-primary/20 dark:text-primary-light/20 transform -scale-x-100" fill="currentColor" viewBox="0 0 32 32" aria-hidden="true">
                     <path d="M9.352 4C4.456 7.456 1 13.12 1 19.36c0 5.088 3.072 8.064 6.624 8.064 3.36 0 5.856-2.688 5.856-5.856 0-3.168-2.208-5.472-5.088-5.472-.576 0-1.344.096-1.536.192.48-3.264 3.552-7.104 6.624-9.024L9.352 4zm16.512 0c-4.8 3.456-8.256 9.12-8.256 15.36 0 5.088 3.072 8.064 6.624 8.064 3.264 0 5.856-2.688 5.856-5.856 0-3.168-2.304-5.472-5.184-5.472-.576 0-1.248.096-1.44.192.48-3.264 3.456-7.104 6.528-9.024L25.864 4z" />
                   </svg>
                   <p className="text-gray-700 dark:text-gray-300 italic relative z-10 pl-6 text-sm leading-relaxed">
                     "{item.feedback}"
                   </p>
                </div>
              </div>
            ))}
          </div>
        ) : (
            <div className="text-center text-gray-500 py-12 mb-12 bg-white/40 dark:bg-gray-800/40 backdrop-blur-sm rounded-2xl border border-dashed border-gray-300 dark:border-gray-700">
                <p>No approved testimonials yet.</p>
                <p className="text-sm mt-1">Be the first to share your feedback!</p>
            </div>
        )}

        {/* Feedback Form Section */}
        <div className="max-w-4xl mx-auto bg-white/70 dark:bg-gray-800/60 backdrop-blur-md rounded-2xl shadow-2xl overflow-hidden border border-white/40 dark:border-gray-700">
          <div className="md:flex h-full">
             {/* Info Side */}
